import { useState } from "react";
import axios from "axios";
import Api from "../api/Api";
export default function ViewLocations() {

  const [zone, setZone] = useState("");
  const [locations, setLocations] = useState([]);
  const [supervisor, setSupervisor] = useState("");

  const handleShow = async () => {
    if (!zone) {
      return alert("Please select zone");
    }

    try {
   const res = await axios.get(
  `${Api.get_Locations_By_Zone}/${encodeURIComponent(zone)}`
);

      setSupervisor(res.data.supervisor);
      setLocations(res.data.locations);

    } catch (err) {
      alert(err.response?.data?.message);
    }
  };

  return (
    <div className="min-h-screen mx-auto ">
   <div className="mb-8 bg-[#4CBB17]/40 px-8">
        <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
          <img
            src="/garbageVehicle.jpeg"
            alt="CleanTrack Logo"
            className="w-16 h-16 object-contain"
          />

          CleanTrack
        </h1>
        <p className="text-gray-900  p-2  ">
          Smart Waste Management Control Center
        </p>
      </div>
      <h1 className="text-4xl font-bold text-center text-green-700 mb-10">
        📍 See the MANIT Locations
      </h1>

      <div className="flex justify-center gap-4 ">

        <select
          value={zone}
          onChange={(e) => setZone(e.target.value)}
          className="border rounded-lg px-4 py-2 w-72"
        >
          <option value="">Select Zone</option>
          
          <option>Hostel Zone 1</option>
          <option>Hostel Zone 2</option>
          <option>Academic Zone</option>
          <option>Colony Zone</option>
        </select>

        <button
          onClick={handleShow}
          className="bg-green-600 text-white px-6 rounded-lg"
        >
          Show
        </button>

      </div>

      {locations.length > 0 && (

    <div className="mt-10 flex flex-col items-center">

  <h2 className="text-2xl font-bold text-green-700 mb-2">
    Supervisor
  </h2>

  <p className="text-xl font-semibold text-blue-700 mb-8">
    {supervisor}
  </p>

  <div className="grid grid-cols-2 md:grid-cols-3 gap-5">

    {locations.map((loc) => (
      <div
        key={loc._id}
        className="w-48 h-20 flex items-center justify-center rounded-xl border border-green-300 bg-green-50 shadow hover:shadow-lg hover:scale-105 transition duration-200"
      >
        <span className="font-medium text-gray-800">
          📍 {loc.locationName}
        </span>
      </div>
    ))}

  </div>

</div>

      )}

    </div>
  );
}
